SELECT t1.id, t1.report_count, t1.report_type, t2.task_code, -- t4.product_id product_id1, -- t4.sample_name, t1.count_price, DATE (t1.request_date) request_date, t3.sample_id, t4.sample_code, t4.alias_name sample_name1, t4.specs, t4.outward, t4.product_id, t5.id id_item, t5.state, t5.origin_url, t6.check_item_id, t5.check_item_name, t9.specs_content, t9.check_result, t9.judge_result, t6.coordinate, t7.specs_content value, CONCAT(t7.check_basis_code, ":", t7.condition_value) label FROM test_entrusted_info t1 LEFT JOIN test_task t2 ON t2.entrustment_id = t1.id LEFT JOIN test_entrusted_sample_details_rel t3 ON t1.id = t3.entrustment_id LEFT JOIN test_sample t4 ON t3.sample_id = t4.id LEFT JOIN test_entrusted_sample_checkitem_rel t5 ON t1.id = t5.entrust_id AND t4.id = t5.sample_id LEFT JOIN test_product_item t6 ON t5.check_item_id = t6.check_item_id LEFT JOIN test_report_qualifcation t7 ON t6.check_item_id = t7.check_item_id left join test_report_record t8 on t1.id = t8.entrustment_id left join test_report_record_detail t9 on t8.id = t9.record_id AND t5.check_item_id = t9.check_item_id AND t2.id = t9.task_id AND t4.id = t9.sample_id WHERE t2.id = #{taskId} and t5.task_id = #{taskId}
and t5.dept_id in
#{id}

SELECT t1.id, t1.report_count, t1.report_type, t2.task_code, -- t4.product_id product_id1, -- t4.sample_name, t1.count_price, DATE (t1.request_date) request_date, t3.sample_id, t4.sample_code, t4.sample_name sample_name1, t4.alias_name alias_name, t4.specs, t4.outward, t4.product_id, t5.id id_item, t5.state, t5.origin_url, t6.check_item_id, t5.check_item_name, t9.specs_content, t9.check_result, t9.judge_result, t6.coordinate, t7.specs_content value, CONCAT(t7.check_basis_code, ":", t7.condition_value) label FROM test_entrusted_info t1 LEFT JOIN test_task t2 ON t2.entrustment_id = t1.id LEFT JOIN test_entrusted_sample_details_rel t3 ON t1.id = t3.entrustment_id LEFT JOIN test_sample t4 ON t3.sample_id = t4.id LEFT JOIN test_entrusted_sample_checkitem_rel t5 ON t1.id = t5.entrust_id AND t4.id = t5.sample_id LEFT JOIN test_product_item t6 ON t5.check_item_id = t6.check_item_id LEFT JOIN test_report_qualifcation t7 ON t6.check_item_id = t7.check_item_id left join test_report_record t8 on t1.id = t8.entrust_id left join test_report_record_detail t9 on t8.id = t9.record_id AND t5.check_item_id = t9.check_item_id AND t2.id = t9.task_id AND t4.id = t9.sample_id WHERE t2.id = #{taskId} and t5.task_id = #{taskId}
and t5.dept_id in
#{id}

SELECT t1.id, t1.report_count, t1.report_type, t2.task_code, t4.product_id product_id1, t4.sample_name, t1.count_price, DATE (t1.request_date) request_date, t3.sample_id, t4.sample_code, t4.sample_name sample_name1, t4.specs, t4.outward, t4.product_id, t5.id id_item, t5.state, t5.origin_url, t6.check_item_id, t5.check_item_name, t9.specs_content, t9.check_result, t9.judge_result, t6.coordinate, t7.specs_content value, CONCAT(t7.check_basis_code, ":", t7.condition_value) label FROM test_entrusted_info t1 LEFT JOIN test_task t2 ON t2.entrustment_id = t1.id LEFT JOIN test_entrusted_sample_details_rel t3 ON t1.id = t3.entrustment_id LEFT JOIN test_sample t4 ON t3.sample_id = t4.id LEFT JOIN test_entrusted_sample_checkitem_rel t5 ON t1.id = t5.entrust_id AND t4.id = t5.sample_id LEFT JOIN test_product_item t6 ON t5.check_item_id = t6.check_item_id LEFT JOIN test_report_qualifcation t7 ON t6.check_item_id = t7.check_item_id left join test_report_record t8 on t1.id = t8.entrustment_id left join test_report_record_detail t9 on t8.id = t9.record_id -- and t5.check_item_id = t9.check_item_id WHERE t2.id = #{taskId} and t5.task_id = #{taskId}
and t5.dept_id in
#{id}

SELECT DISTINCT t1.id, t2.id task_id, t2.task_code, t4.sample_name, t1.count_price, DATE_FORMAT(t1.request_date, '%Y-%m-%d') request_date FROM test_entrusted_info t1 LEFT JOIN test_task t2 ON t2.entrustment_id = t1.id LEFT JOIN test_entrusted_sample_details_rel t3 ON t1.id = t3.entrustment_id LEFT JOIN test_sample t4 ON t3.sample_id = t4.id left join test_entrusted_sample_checkitem_rel t5 on t1.id = t5.entrust_id and t4.id = t5.sample_id where t2.task_code is not null and t2.state = 4
and t2.dept_id in
#{id}

SELECT t2.id as checkItemId, t2.check_item_name as checkItemName, t2.specs_content as specsContent, t2.check_result checkResult, t2.judge_result as judgeResult FROM test_report_record as t1 LEFT JOIN test_entrusted_sample_checkitem_rel t3 ON t1.entrustment_id = t3.entrust_id LEFT JOIN test_report_record_detail as t2 ON t1.id = t2.record_id AND t3.check_item_id = t2.check_item_id WHERE t1.state !=2 and t1.id = #{id} and t3.task_id = #{taskId} and t2.id is not NULL
and t3.dept_id in
#{id}

