mapper.select:
SELECT t2.entrustment_id id, t1.id taskFlowId, t2.id taskId, t2.task_code taskCode, t2.task_price countPrice, STR_TO_DATE(t1.task_flow_date,'%Y-%m-%d') requestDate, t1.remark, t1.record_id recordId, t1.state, t3.type As reportType, IFNULL( t3.state, t4.state ) reportState, IFNULL( IFNULL( t3.report_code, t4.report_code ), '——' ) reportCode FROM test_entrusted_task_rel t1 LEFT JOIN test_task t2 ON t1.task_id = t2.id LEFT JOIN test_report_record t3 ON t1.record_id = t3.id LEFT JOIN test_report_record_mid t4 ON t1.record_id = t4.id WHERE t1.type = 1 AND t1.state = #{state}
and t2.task_code like CONCAT('%',#{taskCode},'%')
and t2.dept_id in
#{id}
order by t1.id desc

update.foreach:
update test_report_record
category = '物理章', state = '7', seal_type = #{item.sealType}, sealer = #{item.sealer}, seal_time = #{item.sealTime}
where id = #{item.key}

mapper.select:
SELECT distinct t1.id, t1.entrustment_id, t1.report_code, t1.sample_name, t1.required_completion_time, t1.report_url, t1.number, t1.issuer_time, t1.seal_type, t1.sealer, t1.seal_time, t1.type, t1.category, t1.qys_state, t1.contract_id FROM test_report_record t1 LEFT JOIN test_task t3 ON t1.entrustment_id = t3.entrustment_id WHERE t1.state >= 7
AND t3.dept_id IN
#{id}
AND report_code like concat(concat('%',#{reportCode}),'%')
AND type = #{reportType}
AND category = #{sealType}
AND seal_time >= #{startDate} and seal_time <= #{endDate}
order by t1.seal_time desc

